struct Compare {
    bool operator()(ListNode* a, ListNode* b) {
        return a->val > b->val;
    }
};

class Solution {
public:
    ListNode* mergeKLists(vector<ListNode*>& lists) {
        if (lists.empty()) return nullptr;

        priority_queue<ListNode*, vector<ListNode*>, Compare> heap;

        for (ListNode* list : lists) {
            if (list) {
                heap.push(list);
            }
        }

        ListNode dummy(0);
        ListNode* curr = &dummy;

        while (!heap.empty()) {
            ListNode* node = heap.top();
            curr->next = node;
            curr = curr->next;
            heap.pop();

            if (node->next) {
                heap.push(node->next);
            }
        }

        return dummy.next;
    }
};

